     1→import React, { useEffect, useState, useRef, use } from "react";
     2→import { MoonLoader, BeatLoader } from "react-spinners";
     3→import { motion, AnimatePresence,} from "framer-motion";
     4→import { useInfiniteQuery, useQueryClient } from '@tanstack/react-query';
     5→import './postcards.css';
     6→import {getJournals,} from "../../../../API/Api";
     7→import ParseContent from "./parseData";
     8→import { useInView } from 'react-intersection-observer';
     9→import CalculateText from "./calculateReadingTime";
    10→import { useLocation, useNavigate, } from "react-router-dom";
    11→import VerifiedBadge from "../../Badge/VerifiedBadge";
    12→
    13→import { useAuth } from "../../../Context/useAuth";
    14→import { useAddViewsMutation, useBookMarkMutation, useLikeMutation } from "../../../utils/useMutation";
    15→import formatCounts from "../../../../helpers/fomatCounts";
    16→import debounce from "../../../../helpers/debounce";
    17→import { handleClickProfile, handleCLickContent } from "../../../../helpers/handleClicks";
    18→import formatPostDate from "../../../../helpers/formatDateString";
    19→
    20→
    21→const PostCards = () => {
    22→    const {session, user, openAuthModal} = useAuth();
    23→    const queryClient = useQueryClient();
    24→    const location = useLocation();
    25→
    26→    const navigate = useNavigate();
    27→    const modalRef = useRef(null);
    28→    const timeOutRef = useRef();
    29→    const {ref, inView} = useInView({
    30→        threshold: 0,
    31→        rootMargin: '800px'
    32→    })
    33→    const [postIdSettings, setPostIdSettings] = useState('');
    34→    const [showHeaders, setShowHeaders] = useState(true);
    35→
    36→    const [bookmarkedMessage, setBookmarkedMessage] = useState('');
    37→    const [showBookmarkedMessage, setShowBookmarkedMessage] = useState(null);
    38→
    39→    const handleClickUserProfileOriginal = handleClickProfile(navigate);
    40→    const clickContent = handleCLickContent(navigate);
    41→
    42→    const mutateViews = useAddViewsMutation(session)
    43→
    44→    const handleClickUserProfile = (e, loggedInUserId, clickedUserId) => {
    45→        if(!session){
    46→            e.stopPropagation();
    47→            return openAuthModal();
    48→        }
    49→        handleClickUserProfileOriginal(e, loggedInUserId, clickedUserId);
    50→    }
    51→
    52→    const viewContent = (e, jsonbContent,wholeText, title, userId, name, avatar, created_at, journalId, isLiked, commentsCount, isBookmarked, likesCount, bookmarksCount, badge) =>{
    53→        if(!session){
    54→            e.stopPropagation();
    55→            return openAuthModal();
    56→        }
    57→        const formadata = new FormData();
    58→
    59→        formadata.append('journalId', journalId);
    60→        mutateViews.mutate(formadata);
    61→
    62→        clickContent(e, jsonbContent,wholeText, title, userId, name, avatar, created_at, journalId, isLiked, commentsCount, isBookmarked, likesCount, bookmarksCount, badge )
    63→    }
    64→
    65→    const header_links = [
    66→        {label: 'Writings', path: '/home'},
    67→        {label: 'Opinions', path: '/home/opinions'},
    68→    ]
    69→
    70→    const handleClickHeaderLinks = (path) =>{
    71→        navigate(path);
    72→    }
    73→
    74→    const cardIcons = [
    75→        {
    76→            likeAction: (isLiked) => (
    77→                <svg className="svg-like" xmlns="http://www.w3.org/2000/svg" width="20px" height="20px" viewBox="0 0 24 24" fill="none">
