   123→            </svg>,
   124→
   125→        }
   126→    ]
   127→
   128→    const userId = user?.userData?.[0]?.id || null;
   129→
   130→    const {
   131→        data,
   132→        fetchNextPage,
   133→        hasNextPage,
   134→        isFetchingNextPage,
   135→        isLoading,
   136→    } = useInfiniteQuery({
   137→        queryKey: ['journals', userId],
   138→        queryFn: ({pageParam = null}) => getJournals(pageParam, 5, userId),
   139→        getNextPageParam: (lastPage) => {
   140→            if(lastPage?.hasMore) {
   141→                const lastJournal = lastPage?.data[lastPage?.data?.length - 1]; //get the last array of object using index
   142→                return new Date(lastJournal.created_at).toISOString();
   143→            }
   144→            return undefined;
   145→        } ,
   146→        refetchOnWindowFocus: false
   147→    })
   148→
   149→    const handleClickSettings = (e, postId) =>{
   150→        e.stopPropagation();
   151→        setPostIdSettings(postId === postIdSettings ? null : postId)
   152→    }
   153→
   154→    const mutationLike = useLikeMutation(session, user?.userData?.[0]?.id);
   155→
   156→    const handleClickLike = async(e, journalId, receiverId) => {
   157→        e.stopPropagation();
   158→        if(!session) return openAuthModal();
   159→        console.log(journalId)
   160→        mutationLike.mutate({journalId, receiverId}) //passing this into mutationFn {journalId: the id}
   161→    }
   162→    const debounceClickLike = debounce(handleClickLike, 300)
   163→
   164→
   165→    const mutationBookmark = useBookMarkMutation(session);
   166→
   167→    const handleClickBookmark = async(e, journalId,) =>{
   168→        e.stopPropagation();
   169→        if(!session) return openAuthModal();
   170→        console.log(journalId)
   171→        // mutationBookmark.mutate({journalId});
   172→        const response = await mutationBookmark.mutateAsync({journalId})
   173→        if(response.message === 'success'){
   174→            setBookmarkedMessage('Post was added to your Bookmarks')
   175→            setShowBookmarkedMessage(journalId);
   176→            setTimeout(() =>{
   177→                setShowBookmarkedMessage(null)
   178→                setBookmarkedMessage('')
   179→            }, 2500)
   180→        } else {
   181→            setBookmarkedMessage('Post was removed from your Bookmarks')
   182→            setShowBookmarkedMessage(journalId);
   183→            setTimeout(() =>{
   184→                setShowBookmarkedMessage(null)
   185→                setBookmarkedMessage('')
   186→            }, 2500)
   187→        }
   188→        console.log(response.message);
   189→    }
   190→
   191→    const debounceClickBookmark = debounce(handleClickBookmark, 100);
   192→
   193→
   194→    const isLoadingMore = isFetchingNextPage || !hasNextPage;
   195→    useEffect(() =>{
   196→        if(inView && !isLoadingMore) {
   197→            fetchNextPage();
   198→        }
   199→    }, [inView, fetchNextPage, isLoadingMore])
   200→
   201→
   202→    useEffect(() => {
   203→       const handleClickOutside = (e) =>{
   204→        if(modalRef.current && !modalRef.current.contains(e.target)){
   205→            setPostIdSettings(null)
   206→        }
   207→       }
   208→       window.addEventListener('click', handleClickOutside)
   209→
   210→       return() => {
   211→        window.removeEventListener('click', handleClickOutside)
   212→       }
   213→    }, [])
   214→
   215→    useEffect(() =>{
   216→        const scroll = (e) =>{
   217→            setShowHeaders(!showHeaders)
   218→
   219→            if(timeOutRef.current){
   220→                clearTimeout(timeOutRef.current);
   221→            }
   222→            timeOutRef.current = setTimeout(() => {
   223→                setShowHeaders(showHeaders)
   224→            }, 100);
   225→        }
   226→        document.addEventListener('scroll', scroll, true);
   227→        return() =>{
   228→            if(timeOutRef.current){
   229→                clearTimeout(timeOutRef.current);
   230→            }
   231→            document.removeEventListener('scroll', scroll, true)
   232→        }
   233→    }, [])
   234→
   235→    useEffect(() =>{
   236→        console.log(data)
   237→    }, [data])
   238→
   239→    const journals = data?.pages?.flatMap((page) => page.data || []) || [];
   240→
   241→    if(isLoading) {
   242→        return(
   243→            <>
   244→            <div className="postcards-parent-loading-container">
   245→                <MoonLoader loading={isLoading} color="rgba(0, 0, 0, 1)" speedMultiplier={1} size={20}/>
   246→            </div>
   247→            </>
   248→        )
   249→    }
   250→
   251→    if(journals?.length === 0 && !isLoading) {
   252→        return(
   253→            <div className="postcards-parent-container">
   254→                <div>No post availabe...</div>
   255→            </div>
   256→        )
   257→    }
   258→    return(
   259→        <>
   260→        <AnimatePresence>
   261→            {showHeaders && (
   262→                <motion.div
   263→                className="newsfeed-header"
   264→                initial={{opacity: 0}}
   265→                animate={{opacity: 1, transition: {type: 'spring', stiffness: 300, damping: 25, mass: 0.8}}}
   266→                exit={{ opacity: 0, y: -20,
   267→                        transition: {
   268→                        duration: 0.2,
   269→                        ease: "easeOut"
   270→                        }
   271→                }}
   272→                >
   273→
   274→                    {header_links.map((header_link, index) => (
   275→                        <div key={index} className="header-links">
   276→                            <div onClick={() => handleClickHeaderLinks(header_link.path) } className='header-link'>
   277→                                {header_link.label}
   278→                                <div className={header_link.path === location.pathname ? "header-underline" : ''}/>
   279→                            </div>
   280→                        </div>
   281→                    ))}
   282→
   283→                </motion.div>
   284→            )}
   285→            </AnimatePresence>
   286→
   287→        <AnimatePresence>
   288→        <div className="postcards-parent-container">
   289→            {journals.map((journal, index) => {
   290→                const parsedContent = ParseContent(journal.content)
   291→                const isLiked = journal?.has_liked;
   292→                const isBookmarked = journal?.has_bookmarked;
   293→                return(
   294→                    <motion.div
   295→                        className="cards"
   296→                        key={journal.id}
   297→                        initial={{opacity: 0, y: 12}}
   298→                        animate={{opacity: 1, y: 0}}
   299→                        transition={{duration: 0.3, ease: 'easeOut'}}
   300→                    >
   301→
   302→                        {parsedContent.firstImage && (
   303→                            <img
   304→                                className="card-image-banner"
   305→                                src={parsedContent.firstImage.src}
   306→                                alt=""
   307→                                loading="lazy"
   308→                                onClick={(e) => viewContent(e, journal.content, parsedContent.wholeText, journal.title, journal.users.id, journal.users.name, journal.users.image_url, journal.created_at, journal.id, journal.has_liked, journal.comment_count?.[0]?.count, journal.has_bookmarked, journal.like_count?.[0].count, journal.bookmark_count?.[0].count, journal.users.badge)}
   309→                            />
   310→                        )}
   311→
   312→                        <div className="card-content">
   313→                            <div onClick={(e) => viewContent(e, journal.content, parsedContent.wholeText, journal.title, journal.users.id, journal.users.name, journal.users.image_url, journal.created_at, journal.id, journal.has_liked, journal.comment_count?.[0]?.count, journal.has_bookmarked, journal.like_count?.[0].count, journal.bookmark_count?.[0].count, journal.users.badge)} className="content-container">
   314→                                <div className="feed-text-content-container">
   315→                                    <div className="feed-title-content">
   316→                                        <h2 className="feed-title">{journal.title.length > 55 ? `${journal.title.substring(0, 55)}...` : journal.title}</h2>
   317→                                    </div>
   318→                                    <p className="feed-text-content">{parsedContent.slicedText}</p>
   319→                                </div>
   320→                            </div>
   321→                        </div>
   322→
   323→                        <div className="card-icons-container">
   324→                            <div className="user-info-child-container">
