   326→                                    <img loading="lazy" className="user-info-avatar" src={journal.users.image_url || '/assets/profile.jpg'} alt="" />
   327→                                </div>
   328→                                <div onClick={(e) => handleClickUserProfile(e, user?.userData?.[0].id, journal.users.id)} className="user-name-container">
   329→                                    <p className="user-newsfeed-name">{journal.users.name}</p>
   330→                                    <VerifiedBadge badge={journal.users.badge} size={14} />
   331→                                </div>
   332→                                <div className="name-info-separator">•</div>
   333→                                <p className="user-post-date">{formatPostDate(journal.created_at)}</p>
   334→                            </div>
   335→
   336→                            {cardIcons && (
   337→                                cardIcons.map((icon, index) =>(
   338→                                    <div key={index} className="icon-container">
   339→
   340→                                        {icon.likeAction && (
   341→                                            <div onClick={(e) => icon.action(e, journal.id, journal.users.id, user?.userData?.[0].image_url, user?.userData?.[0].name, user?.userData?.[0].user_email)} id="card-icons" className={icon.className}>
   342→                                                {icon.likeAction && icon.likeAction(isLiked)}
   343→                                            </div>
   344→                                        )}
   345→
   346→                                        {icon.commentAction && (
   347→                                            <div onClick={(e) => icon.commentAction(e, journal.content,parsedContent.wholeText, journal.title, journal.users.id, journal.users.name, journal.users.image_url, journal.created_at, journal.id, journal.has_liked, journal.comment_count?.[0]?.count, journal.has_bookmarked, journal.like_count?.[0].count, journal.bookmark_count?.[0].count)} id="card-icons" className={icon.className}>
   348→                                                {icon.label}
   349→                                            </div>
   350→                                        )}
   351→
   352→                                        {icon.bookmarkAction && (
   353→                                            <div onClick={(e) => icon.bookmarkAction(e, journal.id)} id="card-icons" className={icon.className}>
   354→                                                {icon.checkBookrmark(isBookmarked)}
   355→                                            </div>
   356→                                        )}
   357→
   358→                                        {icon.iconView && (
   359→                                            <div id="card-icons-view">
   360→                                                {icon.iconView}
   361→                                            </div>
   362→                                        )}
   363→
   364→                                        {icon.countLike && icon.countLike(journal.like_count?.[0].count)}
   365→                                        {icon.countComments && icon.countComments(journal.comment_count?.[0]?.count)}
   366→                                        {icon.countBookmarks && icon.countBookmarks(journal.bookmark_count?.[0].count)}
   367→                                        {icon.iconCount && icon.iconCount(journal?.views)}
   368→                                    </div>
   369→                                ))
