   371→
   372→                            <div className="reading-time-container">
   373→                                <p className="reading-time-text">{CalculateText(parsedContent.wholeText)}</p>
   374→                            </div>
   375→
   376→                            <div className="user-post-settings">
   377→                                <svg onClick={(e) => handleClickSettings(e, journal.id)} xmlns="http://www.w3.org/2000/svg" height="24px" viewBox="0 -960 960 960" width="24px" fill="currentColor"><path d="M240-400q-33 0-56.5-23.5T160-480q0-33 23.5-56.5T240-560q33 0 56.5 23.5T320-480q0 33-23.5 56.5T240-400Zm240 0q-33 0-56.5-23.5T400-480q0-33 23.5-56.5T480-560q33 0 56.5 23.5T560-480q0 33-23.5 56.5T480-400Zm240 0q-33 0-56.5-23.5T640-480q0-33 23.5-56.5T720-560q33 0 56.5 23.5T800-480q0 33-23.5 56.5T720-400Z"/></svg>
   378→                                {postIdSettings === journal.id && (
   379→                                    <motion.div
   380→                                    initial={{opacity:0 ,scale:0}}
   381→                                    animate={{opacity:1, scale:1, transition: {type: "tween", duration: 0.3}}}
   382→                                    exit={{opacity:0, scale:0, transition: {type: "tween", duration: 0.3}}}
   383→                                    ref={modalRef} className="setting-modal"
   384→                                    >
   385→                                        <p onClick={() => console.log('clicked')}>{journal.title}</p>
   386→                                    </motion.div>
   387→                                )}
   388→                            </div>
   389→                        </div>
   390→
